function finiteInterval(value, fallback = 5000) {
  const parsed = Number(value);
  return Number.isFinite(parsed) ? Math.max(1000, parsed) : fallback;
}

function optionalArray(value) {
  return Array.isArray(value) ? value : [];
}

function errorMessage(error) {
  return error?.message || String(error);
}

function normalizeAvailable(available = {}) {
  return {
    jobBoard: optionalArray(available.jobBoard),
    noticeBoards: optionalArray(available.noticeBoards),
    noticeBoardPosts: optionalArray(available.noticeBoardPosts),
    guilds: optionalArray(available.guilds),
    guildRosters: optionalArray(available.guildRosters),
    guildContracts: optionalArray(available.guildContracts),
    propertyInteractions: optionalArray(available.propertyInteractions),
    rentableProperties: optionalArray(available.rentableProperties),
    purchasableProperties: optionalArray(available.purchasableProperties),
    propertySaleListings: optionalArray(available.propertySaleListings),
    storageAuctionEvents: optionalArray(available.storageAuctionEvents),
    storageAuctionLots: optionalArray(available.storageAuctionLots),
    courierBoard: optionalArray(available.courierBoard),
    businessOrders: optionalArray(available.businessOrders),
    businessListings: optionalArray(available.businessListings),
    recipes: optionalArray(available.recipes),
    resourceNodes: optionalArray(available.resourceNodes),
    taxiRoutes: optionalArray(available.taxiRoutes),
    taxiContracts: optionalArray(available.taxiContracts),
    territories: optionalArray(available.territories),
    wantedBoard: optionalArray(available.wantedBoard),
    medicalCalls: optionalArray(available.medicalCalls),
    spells: optionalArray(available.spells)
  };
}

export function normalizeRpOverview(payload = {}) {
  const overview = payload && typeof payload === 'object' ? payload : {};

  return {
    character: overview.character || null,
    inventory: optionalArray(overview.inventory),
    equipment: optionalArray(overview.equipment),
    professions: optionalArray(overview.professions),
    professionMemberships: optionalArray(overview.professionMemberships),
    professionInvitations: optionalArray(overview.professionInvitations),
    spells: optionalArray(overview.spells),
    guildMemberships: optionalArray(overview.guildMemberships),
    guildDues: optionalArray(overview.guildDues),
    guildContractClaims: optionalArray(overview.guildContractClaims),
    territoryOffices: optionalArray(overview.territoryOffices),
    knownCharacters: optionalArray(overview.knownCharacters),
    reputation: optionalArray(overview.reputation),
    properties: optionalArray(overview.properties),
    propertyRecoveryCases: optionalArray(overview.propertyRecoveryCases),
    propertyCharges: optionalArray(overview.propertyCharges),
    storageAuctionEvents: optionalArray(overview.storageAuctionEvents),
    storageAuctionLots: optionalArray(overview.storageAuctionLots),
    businesses: optionalArray(overview.businesses),
    jobs: optionalArray(overview.jobs),
    courierDeliveries: optionalArray(overview.courierDeliveries),
    mailInbox: optionalArray(overview.mailInbox),
    taxiContracts: optionalArray(overview.taxiContracts),
    taxiRides: optionalArray(overview.taxiRides),
    medicalCalls: optionalArray(overview.medicalCalls),
    activeCuff: overview.activeCuff || null,
    activeArrest: overview.activeArrest || null,
    activeJailSentence: overview.activeJailSentence || null,
    custody: overview.custody || null,
    jailTasks: optionalArray(overview.jailTasks),
    activeInjury: overview.activeInjury || null,
    available: normalizeAvailable(overview.available),
    ownerState: optionalArray(overview.ownerState)
  };
}

/**
 * @typedef {Object} RpOverviewServiceOptions
 * @property {{ get: (path: string, options?: any) => Promise<any> }} http
 * @property {{ getState: () => Record<string, any> }} joinClient
 * @property {number} [intervalMs]
 * @property {(message: string) => void} [logger]
 * @property {(eventType: string, details?: Record<string, unknown>) => (Promise<unknown> | unknown)} [reportDiagnostic]
 * @property {(overview: Record<string, unknown>, reason: string) => void} [onUpdate]
 * @property {() => number} [now]
 */

/**
 * @param {RpOverviewServiceOptions} options
 */
export function createRpOverviewService({
  http,
  joinClient,
  intervalMs = 5000,
  logger = (_message) => {},
  reportDiagnostic = async (_eventType, _details = {}) => {},
  onUpdate = (_overview, _reason) => {},
  now = () => Date.now()
}) {
  if (!http || typeof http.get !== 'function') {
    throw new Error('http adapter with get is required for RP overview');
  }
  if (!joinClient || typeof joinClient.getState !== 'function') {
    throw new Error('joinClient with getState is required for RP overview');
  }

  const state = {
    overview: null,
    intervalMs: finiteInterval(intervalMs),
    lastAttemptAt: 0,
    lastFetchedAt: null,
    lastCharacterId: null,
    lastError: null,
    inFlight: false
  };

  function report(eventType, details = {}) {
    Promise.resolve(reportDiagnostic(eventType, details)).catch((error) => {
      logger(`diagnostic failed: ${errorMessage(error)}`);
    });
  }

  function resetForCharacter(characterId) {
    if (state.lastCharacterId === characterId) {
      return;
    }

    state.overview = null;
    state.lastFetchedAt = null;
    state.lastError = null;
    state.lastCharacterId = characterId;
  }

  function readReadySession() {
    const joinState = joinClient.getState();
    if (joinState.phase !== 'joined') {
      state.overview = null;
      state.lastCharacterId = null;
      return null;
    }

    const auth = joinState.auth || null;
    const character = joinState.character || null;
    const accountId = typeof auth?.accountId === 'string' ? auth.accountId.trim() : '';
    const sessionToken = typeof auth?.sessionToken === 'string' ? auth.sessionToken.trim() : '';
    const characterId = typeof character?.id === 'string' ? character.id.trim() : '';
    if (!accountId || !sessionToken || !characterId) {
      return null;
    }

    resetForCharacter(characterId);
    return {
      auth: { accountId, sessionToken },
      characterId
    };
  }

  async function refresh(reason = 'manual', currentTime = now()) {
    if (state.inFlight) {
      return false;
    }

    const session = readReadySession();
    if (!session) {
      return false;
    }

    state.inFlight = true;
    state.lastAttemptAt = currentTime;
    try {
      const overview = normalizeRpOverview(await http.get(
        `/characters/${encodeURIComponent(session.characterId)}/overview`,
        { auth: session.auth }
      ));
      state.overview = overview;
      state.lastFetchedAt = currentTime;
      state.lastError = null;
      onUpdate(overview, reason);
      report('rp_overview_refresh', {
        reason,
        characterId: session.characterId
      });
      return true;
    } catch (error) {
      state.lastError = errorMessage(error);
      logger(`RP overview refresh failed: ${state.lastError}`);
      report('rp_overview_failed', {
        reason,
        characterId: session.characterId,
        error: state.lastError
      });
      return false;
    } finally {
      state.inFlight = false;
    }
  }

  function tick(currentTime = now()) {
    if (state.inFlight || currentTime - state.lastAttemptAt < state.intervalMs) {
      return false;
    }

    const session = readReadySession();
    if (!session) {
      return false;
    }

    void refresh('tick', currentTime);
    return true;
  }

  function getOverview() {
    return state.overview ? normalizeRpOverview(state.overview) : null;
  }

  return {
    state,
    tick,
    refresh,
    getOverview,
    getState() {
      return {
        ...state,
        overview: getOverview()
      };
    }
  };
}
