function text(value, fallback = '') {
  return typeof value === 'string' && value.trim() !== '' ? value.trim() : fallback;
}

function locationKey(value) {
  return text(value, 'unknown').toLowerCase().replace(/[^a-z0-9]/g, '');
}

const worldspaceAliases = new Map([
  ['skyrim', 'Tamriel'],
  ['tamriel', 'Tamriel']
]);

const cellAliases = new Map([
  ['sleepinggiantinn', 'RiverwoodSleepingGiantInn'],
  ['riverwoodsleepinggiantinn', 'RiverwoodSleepingGiantInn']
]);

function canonicalWorldspace(value) {
  const original = text(value, 'unknown');
  return worldspaceAliases.get(locationKey(original)) || original;
}

function canonicalCell(value) {
  const original = text(value, 'unknown');
  return cellAliases.get(locationKey(original)) || original;
}

function sameCell(a, b) {
  return locationKey(canonicalWorldspace(a?.worldspace)) !== 'unknown'
    && locationKey(canonicalCell(a?.cell)) !== 'unknown'
    && locationKey(canonicalWorldspace(a?.worldspace)) === locationKey(canonicalWorldspace(b?.worldspace))
    && locationKey(canonicalCell(a?.cell)) === locationKey(canonicalCell(b?.cell));
}

function toPromise(value) {
  return value && typeof value.then === 'function' ? value : Promise.resolve(value);
}

function numberValue(value, fallback = 0) {
  const parsed = Number(value);
  return Number.isFinite(parsed) ? parsed : fallback;
}

function peerFingerprint(peer) {
  return [
    peer.clientId,
    peer.displayName,
    peer.overlayName,
    peer.activeTitle?.title,
    peer.activeTitle?.visibility,
    peer.position?.worldspace,
    peer.position?.cell,
    peer.position?.x,
    peer.position?.y,
    peer.position?.z,
    peer.position?.rotationZ,
    peer.speaking
  ].map((part) => String(part ?? '')).join('|');
}

function peerToAvatar(peer, baseFormId) {
  return {
    clientId: text(peer?.clientId),
    displayName: text(peer?.overlayName, text(peer?.displayName, text(peer?.clientId, 'Player'))),
    characterName: text(peer?.displayName, text(peer?.clientId, 'Player')),
    activeTitle: peer?.activeTitle || null,
    baseFormId,
    speaking: Boolean(peer?.speaking),
    worldspace: canonicalWorldspace(peer?.position?.worldspace),
    cell: canonicalCell(peer?.position?.cell),
    x: numberValue(peer?.position?.x),
    y: numberValue(peer?.position?.y),
    z: numberValue(peer?.position?.z),
    rotationZ: numberValue(peer?.position?.rotationZ)
  };
}

/**
 * @param {{
 *   adapter: {
 *     spawnAvatar: (avatar: any) => unknown,
 *     updateAvatar?: (reference: unknown, avatar: any, previousAvatar?: any) => unknown,
 *     despawnAvatar?: (reference: unknown, avatar: any, reason: string) => unknown,
 *     getReferenceId?: (reference: unknown) => unknown
 *   },
 *   getPosition?: () => Record<string, unknown>,
 *   storage?: Record<string, unknown> | null,
 *   logger?: (message: string) => void,
 *   onBridgeEvent?: (event: Record<string, unknown>) => void,
 *   canRender?: () => boolean,
 *   localCellOnly?: boolean,
 *   baseFormId?: string
 * }} options
 */
export function createPeerAvatarBridge({
  adapter,
  getPosition = () => ({}),
  storage = null,
  logger = (_message) => {},
  onBridgeEvent = (_event) => {},
  canRender = () => true,
  localCellOnly = true,
  baseFormId = '0x00000007'
}) {
  if (!adapter || typeof adapter.spawnAvatar !== 'function') {
    throw new Error('Peer avatar bridge adapter with spawnAvatar is required');
  }

  const state = {
    peers: new Map(),
    renderedPeers: new Map(),
    failedPeers: new Map(),
    lastError: null
  };

  function emitBridgeEvent(event) {
    try {
      onBridgeEvent(event);
    } catch (error) {
      logger(`peer avatar event callback failed: ${error?.message || String(error)}`);
    }
  }

  function snapshotStorage() {
    if (!storage || typeof storage !== 'object') {
      return;
    }

    storage.skyrimRpPeerAvatarBridge = {
      peerClientIds: [...state.peers.keys()],
      renderedClientIds: [...state.renderedPeers.keys()],
      failedClientIds: [...state.failedPeers.keys()],
      lastError: state.lastError
    };
  }

  function shouldRender(peer) {
    return peer?.clientId
      && peer?.position
      && canRender()
      && (!localCellOnly || sameCell(peer.position, getPosition()));
  }

  function forgetFailure(clientId) {
    state.failedPeers.delete(clientId);
  }

  function despawnLocal(clientId, reason = 'server') {
    const rendered = state.renderedPeers.get(clientId);
    if (!rendered) {
      forgetFailure(clientId);
      snapshotStorage();
      return false;
    }

    state.renderedPeers.delete(clientId);
    forgetFailure(clientId);
    toPromise(adapter.despawnAvatar?.(rendered.reference, rendered.avatar, reason)).catch((error) => {
      state.lastError = error?.message || String(error);
      logger(`peer avatar despawn failed clientId=${clientId}: ${state.lastError}`);
    });
    logger(`peer avatar despawned clientId=${clientId} reason=${reason}`);
    emitBridgeEvent({
      bridgeEvent: 'despawned',
      clientId,
      reason,
      displayName: rendered.avatar?.displayName || '',
      referenceId: rendered.referenceId ?? null
    });
    snapshotStorage();
    return true;
  }

  function updateRenderedPeer(clientId, peer) {
    const rendered = state.renderedPeers.get(clientId);
    if (!rendered) {
      return false;
    }

    const avatar = peerToAvatar(peer, baseFormId);
    if (rendered.fingerprint === peerFingerprint(peer)) {
      return true;
    }

    const previousAvatar = rendered.avatar;
    rendered.avatar = avatar;
    rendered.fingerprint = peerFingerprint(peer);
    toPromise(adapter.updateAvatar?.(rendered.reference, avatar, previousAvatar)).catch((error) => {
      state.lastError = error?.message || String(error);
      logger(`peer avatar update failed clientId=${clientId}: ${state.lastError}`);
      emitBridgeEvent({
        bridgeEvent: 'update_failed',
        clientId,
        displayName: avatar.displayName,
        error: state.lastError
      });
      snapshotStorage();
    });
    snapshotStorage();
    return true;
  }

  function renderPeer(peer) {
    if (!shouldRender(peer)) {
      return false;
    }

    if (state.renderedPeers.has(peer.clientId)) {
      return updateRenderedPeer(peer.clientId, peer);
    }

    const fingerprint = peerFingerprint(peer);
    if (state.failedPeers.get(peer.clientId) === fingerprint) {
      return false;
    }

    const avatar = peerToAvatar(peer, baseFormId);
    try {
      const reference = adapter.spawnAvatar(avatar);
      if (!reference) {
        state.failedPeers.set(peer.clientId, fingerprint);
        logger(`peer avatar spawn skipped clientId=${peer.clientId}: adapter returned no reference`);
        emitBridgeEvent({
          bridgeEvent: 'spawn_skipped',
          clientId: peer.clientId,
          displayName: avatar.displayName,
          baseFormId: avatar.baseFormId,
          error: 'adapter returned no reference'
        });
        snapshotStorage();
        return false;
      }

      const referenceId = adapter.getReferenceId?.(reference);
      state.renderedPeers.set(peer.clientId, {
        peer,
        avatar,
        reference,
        referenceId,
        fingerprint
      });
      forgetFailure(peer.clientId);
      logger(`peer avatar spawned ${avatar.displayName} clientId=${peer.clientId}`);
      emitBridgeEvent({
        bridgeEvent: 'rendered',
        clientId: peer.clientId,
        displayName: avatar.displayName,
        baseFormId: avatar.baseFormId,
        referenceId: referenceId ?? null
      });
      snapshotStorage();
      return true;
    } catch (error) {
      state.lastError = error?.message || String(error);
      if (!error?.transient) {
        state.failedPeers.set(peer.clientId, fingerprint);
      }
      logger(`peer avatar spawn failed clientId=${peer.clientId}: ${state.lastError}`);
      emitBridgeEvent({
        bridgeEvent: 'spawn_failed',
        clientId: peer.clientId,
        displayName: avatar.displayName,
        baseFormId: avatar.baseFormId,
        error: state.lastError,
        transient: Boolean(error?.transient)
      });
      snapshotStorage();
      return false;
    }
  }

  function syncRenderedPeers() {
    for (const [clientId, rendered] of state.renderedPeers) {
      const peer = state.peers.get(clientId);
      if (!peer || !shouldRender(peer)) {
        despawnLocal(clientId, peer ? 'left_cell' : 'server_removed');
      } else {
        rendered.peer = peer;
        updateRenderedPeer(clientId, peer);
      }
    }

    for (const peer of state.peers.values()) {
      renderPeer(peer);
    }

    snapshotStorage();
  }

  function applyPeer(peer) {
    if (!peer?.clientId) {
      return;
    }

    state.peers.set(peer.clientId, peer);
    forgetFailure(peer.clientId);
  }

  function handlePeerEvent(event) {
    if (!event || typeof event !== 'object') {
      return;
    }

    if (event.type === 'snapshot') {
      const nextIds = new Set();
      state.peers.clear();
      for (const peer of Array.isArray(event.peers) ? event.peers : []) {
        if (peer?.clientId) {
          state.peers.set(peer.clientId, peer);
          nextIds.add(peer.clientId);
        }
      }

      for (const clientId of state.renderedPeers.keys()) {
        if (!nextIds.has(clientId)) {
          despawnLocal(clientId, 'snapshot_removed');
        }
      }
      syncRenderedPeers();
      return;
    }

    if (event.type === 'left') {
      state.peers.delete(event.clientId);
      despawnLocal(event.clientId, 'left');
      syncRenderedPeers();
      return;
    }

    if (event.peer) {
      const peer = event.type === 'voice_state'
        ? { ...event.peer, speaking: Boolean(event.speaking) }
        : event.peer;
      applyPeer(peer);
      syncRenderedPeers();
    }
  }

  function tick() {
    syncRenderedPeers();
  }

  return {
    state,
    handlePeerEvent,
    tick,
    getState() {
      return {
        peerClientIds: [...state.peers.keys()],
        renderedClientIds: [...state.renderedPeers.keys()],
        failedClientIds: [...state.failedPeers.keys()],
        lastError: state.lastError
      };
    }
  };
}
