const defaultGoldFormId = 0x0000000f;

function finiteInterval(value, fallback = 3000) {
  const parsed = Number(value);
  return Number.isFinite(parsed) ? Math.max(1000, parsed) : fallback;
}

function errorMessage(error) {
  return error?.message || String(error);
}

function resolveGoldForm(Game, goldFormId) {
  let getFormError = null;

  if (typeof Game.getForm === 'function') {
    try {
      const gold = Game.getForm(goldFormId);
      if (gold) {
        return gold;
      }
    } catch (error) {
      getFormError = error;
    }
  }

  const gold = Game.getFormEx(goldFormId);
  if (gold) {
    return gold;
  }

  if (getFormError) {
    throw getFormError;
  }

  return null;
}

function resolveGoldContext(Game, goldFormId) {
  const player = Game.getPlayer();
  const gold = resolveGoldForm(Game, goldFormId);
  if (!player || !gold) {
    return null;
  }

  return { player, gold };
}

function normalizedGoldCount(value) {
  if (!Number.isFinite(value) || value < 0) {
    return null;
  }

  return Math.trunc(value);
}

/**
 * @typedef {Object} SkyrimGoldReaderOptions
 * @property {{ getPlayer: () => ({ getItemCount: (form: any) => number, addItem?: (form: any, count: number, silent: boolean) => void, removeItem?: (form: any, count: number, silent: boolean, otherContainer: any) => void } | null), getForm?: (formId: number) => any, getFormEx: (formId: number) => any }} Game
 * @property {number} [goldFormId]
 */

/**
 * @param {SkyrimGoldReaderOptions} options
 * @returns {() => number | null}
 */
export function createSkyrimGoldReader({ Game, goldFormId = defaultGoldFormId }) {
  if (!Game || typeof Game.getPlayer !== 'function' || typeof Game.getFormEx !== 'function') {
    throw new Error('SkyrimPlatform Game API is required for wallet gold reads');
  }

  return function readSkyrimGold() {
    const context = resolveGoldContext(Game, goldFormId);
    if (!context) {
      return null;
    }

    return normalizedGoldCount(context.player.getItemCount(context.gold));
  };
}

/**
 * @param {SkyrimGoldReaderOptions} options
 * @returns {(targetGold: number) => { applied: boolean, before: number | null, after: number | null, delta: number, targetGold: number, reason?: string }}
 */
export function createSkyrimGoldReconciler({ Game, goldFormId = defaultGoldFormId }) {
  if (!Game || typeof Game.getPlayer !== 'function' || typeof Game.getFormEx !== 'function') {
    throw new Error('SkyrimPlatform Game API is required for wallet gold writes');
  }

  return function reconcileSkyrimGold(targetGold) {
    if (!Number.isInteger(targetGold) || targetGold < 0 || targetGold > 2147483647) {
      throw new Error('targetGold must be an integer from 0 to 2147483647');
    }

    const context = resolveGoldContext(Game, goldFormId);
    if (!context) {
      return {
        applied: false,
        before: null,
        after: null,
        delta: 0,
        targetGold,
        reason: 'missing_player_or_gold_form'
      };
    }

    const before = normalizedGoldCount(context.player.getItemCount(context.gold));
    if (before === null) {
      return {
        applied: false,
        before: null,
        after: null,
        delta: 0,
        targetGold,
        reason: 'invalid_current_gold'
      };
    }

    const delta = targetGold - before;
    if (delta === 0) {
      return {
        applied: false,
        before,
        after: before,
        delta,
        targetGold,
        reason: 'already_matched'
      };
    }

    if (delta > 0) {
      if (typeof context.player.addItem !== 'function') {
        throw new Error('SkyrimPlatform player.addItem is required for wallet gold writes');
      }
      context.player.addItem(context.gold, delta, true);
    } else {
      if (typeof context.player.removeItem !== 'function') {
        throw new Error('SkyrimPlatform player.removeItem is required for wallet gold writes');
      }
      context.player.removeItem(context.gold, Math.abs(delta), true, null);
    }

    const after = normalizedGoldCount(context.player.getItemCount(context.gold));
    return {
      applied: true,
      before,
      after,
      delta,
      targetGold
    };
  };
}

/**
 * @typedef {Object} WalletSyncServiceOptions
 * @property {boolean} [enabled]
 * @property {number} [intervalMs]
 * @property {() => (number | null | undefined)} [readGold]
 * @property {() => boolean} [isReady]
 * @property {(gold: number, options: Record<string, unknown>) => boolean} [syncWalletGold]
 * @property {(message: string) => void} [logger]
 * @property {(eventType: string, details?: Record<string, unknown>) => (Promise<unknown> | unknown)} [reportDiagnostic]
 * @property {(error: unknown) => boolean} [isContextError]
 * @property {string} [source]
 * @property {string} [reason]
 * @property {() => number} [now]
 */

/**
 * @param {WalletSyncServiceOptions} [options]
 */
export function createWalletSyncService(options = {}) {
  const {
  enabled = true,
  intervalMs = 3000,
  readGold = () => null,
  isReady = () => false,
  syncWalletGold = (_gold, _options = {}) => false,
  logger = (_message) => {},
  reportDiagnostic = async (_eventType, _details = {}) => {},
  isContextError = (_error) => false,
  source = 'skyrim_gold',
  reason = 'Skyrim gold sync',
  now = () => Date.now()
  } = options;

  const state = {
    enabled: Boolean(enabled),
    intervalMs: finiteInterval(intervalMs),
    lastAttemptAt: 0,
    lastSyncedGold: null,
    contextWarningSent: false,
    readWarningSent: false,
    lastError: null,
    lastSyncedAt: null
  };

  function report(eventType, details = {}) {
    Promise.resolve(reportDiagnostic(eventType, details)).catch((error) => {
      logger(`diagnostic failed: ${errorMessage(error)}`);
    });
  }

  function handleReadError(error) {
    state.lastError = errorMessage(error);

    if (!state.contextWarningSent && isContextError(error)) {
      state.contextWarningSent = true;
      logger('wallet sync waiting for playable world before reading Skyrim gold');
      report('wallet_sync_waiting', {
        error: state.lastError,
        source
      });
      return false;
    }

    if (!state.readWarningSent) {
      state.readWarningSent = true;
      logger(`wallet sync gold read failed: ${state.lastError}`);
    }
    return false;
  }

  function tick(currentTime = now()) {
    if (!state.enabled || currentTime - state.lastAttemptAt < state.intervalMs) {
      return false;
    }

    if (!isReady()) {
      return false;
    }

    state.lastAttemptAt = currentTime;

    let gold;
    try {
      gold = readGold();
    } catch (error) {
      return handleReadError(error);
    }

    if (gold === null || gold === undefined || gold === state.lastSyncedGold) {
      return false;
    }

    if (!Number.isInteger(gold) || gold < 0 || gold > 2147483647) {
      state.lastError = 'gold must be an integer from 0 to 2147483647';
      if (!state.readWarningSent) {
        state.readWarningSent = true;
        logger(`wallet sync gold read failed: ${state.lastError}`);
      }
      return false;
    }

    const sent = syncWalletGold(gold, { source, reason });
    if (!sent) {
      return false;
    }

    state.lastSyncedGold = gold;
    state.lastSyncedAt = currentTime;
    state.contextWarningSent = false;
    state.readWarningSent = false;
    state.lastError = null;
    logger(`wallet sync gold=${gold}`);
    return true;
  }

  return {
    state,
    tick,
    getState() {
      return { ...state };
    }
  };
}
