/** @type {() => any} */
const defaultGetRpOverview = () => null;
const PROFESSION_LEVEL_THRESHOLDS = Object.freeze([0, 25, 75, 150, 250, 375, 525, 700, 900, 1125]);

function optionalArray(value) {
  return Array.isArray(value) ? value : [];
}

function label(value, fallback) {
  return typeof value === 'string' && value.trim() !== '' ? value.trim() : fallback;
}

function humanizedCode(value, fallback = '') {
  const clean = label(value, '');
  if (!clean) {
    return fallback;
  }

  return clean
    .replace(/[_-]+/g, ' ')
    .replace(/\b\w/g, (letter) => letter.toUpperCase());
}

function parseCommsSubmit({ mode = 'local', text = '' } = {}) {
  const cleanText = label(text, '');
  if (!cleanText) {
    return null;
  }

  const slash = cleanText.match(/^\/([a-z]+)(?:\s+([\s\S]*))?$/i);
  if (slash) {
    const command = slash[1].toLowerCase();
    const body = label(slash[2], '');
    if (!body) {
      return null;
    }

    if (['me', 'emote'].includes(command)) {
      return { type: 'expression', kind: 'me', text: body };
    }

    if (command === 'do') {
      return { type: 'expression', kind: 'do', text: body };
    }

    if (['ooc', 'looc', 'b'].includes(command)) {
      return { type: 'expression', kind: 'ooc', text: body };
    }

    if (['roll', 'r'].includes(command)) {
      return { type: 'roll', expression: body };
    }

    if (['local', 'l', 'say', 's'].includes(command)) {
      return { type: 'local', text: body };
    }
  }

  const cleanMode = label(mode, 'local').toLowerCase();
  if (cleanMode === 'roll') {
    return { type: 'roll', expression: cleanText };
  }

  if (['me', 'do', 'ooc'].includes(cleanMode)) {
    return { type: 'expression', kind: cleanMode, text: cleanText };
  }

  return { type: 'local', text: cleanText };
}

function firstAvailableResource(nodes) {
  return nodes.find((node) => !node.state || node.state === 'available') || nodes[0] || null;
}

function resourceNodeList(owner, joinState = {}) {
  const overviewNodes = optionalArray(owner?.available?.resourceNodes);
  if (overviewNodes.length > 0) {
    return overviewNodes;
  }

  if (Array.isArray(joinState.resourceNodes)) {
    return joinState.resourceNodes;
  }

  if (joinState.resourceNodes && typeof joinState.resourceNodes === 'object') {
    return Object.values(joinState.resourceNodes);
  }

  return [];
}

function resourceMatchesAnchor(resource, anchorCode) {
  const cleanAnchor = label(anchorCode, '');
  return cleanAnchor
    && (
      label(resource?.code, '') === cleanAnchor
      || label(resource?.worldReferenceCode, '') === cleanAnchor
    );
}

function resourceDisplayName(resource) {
  return label(resource?.displayName || resource?.code, 'Resource');
}

function firstResourceForAnchor(owner, joinState, anchorCode) {
  const matches = resourceNodeList(owner, joinState)
    .filter((resource) => resourceMatchesAnchor(resource, anchorCode));
  return firstAvailableResource(matches);
}

function firstUnknownPeer(peers) {
  return peers.find((peer) => peer.identityKnown !== true) || peers[0] || null;
}

function firstSpeakingPeer(peers) {
  return peers.find((peer) => peer?.speaking === true) || null;
}

const playerTargeting = {
  maxDistance: 450,
  maxAngleDegrees: 35,
  maxVerticalDifference: 180
};

function finiteNumber(value) {
  const parsed = Number(value);
  return Number.isFinite(parsed) ? parsed : null;
}

function normalizeAngleDegrees(value) {
  const parsed = finiteNumber(value);
  if (parsed === null) {
    return null;
  }

  return ((parsed % 360) + 360) % 360;
}

function angularDifferenceDegrees(left, right) {
  const normalizedLeft = normalizeAngleDegrees(left);
  const normalizedRight = normalizeAngleDegrees(right);
  if (normalizedLeft === null || normalizedRight === null) {
    return null;
  }

  const difference = Math.abs(normalizedLeft - normalizedRight);
  return Math.min(difference, 360 - difference);
}

function positionCellKey(position) {
  if (!position) {
    return '';
  }

  return `${label(position.worldspace, 'unknown').toLowerCase()}::${label(position.cell, 'unknown').toLowerCase()}`;
}

function validPosition(position) {
  if (!position || typeof position !== 'object') {
    return null;
  }

  const x = finiteNumber(position.x);
  const y = finiteNumber(position.y);
  const z = finiteNumber(position.z);
  const rotationZ = finiteNumber(position.rotationZ);
  if (x === null || y === null || z === null || rotationZ === null) {
    return null;
  }

  return {
    worldspace: label(position.worldspace, 'unknown'),
    cell: label(position.cell, 'unknown'),
    x,
    y,
    z,
    rotationZ
  };
}

function peerAimScore(peer, selfPosition) {
  const self = validPosition(selfPosition);
  const target = validPosition(peer?.position);
  if (!self || !target) {
    return null;
  }

  if (positionCellKey(self) !== positionCellKey(target)) {
    return null;
  }

  const dx = target.x - self.x;
  const dy = target.y - self.y;
  const dz = target.z - self.z;
  const planarDistance = Math.sqrt((dx * dx) + (dy * dy));
  if (planarDistance <= 0 || planarDistance > playerTargeting.maxDistance) {
    return null;
  }

  if (Math.abs(dz) > playerTargeting.maxVerticalDifference) {
    return null;
  }

  const targetAngle = normalizeAngleDegrees(Math.atan2(dx, dy) * 180 / Math.PI);
  const angleDifference = angularDifferenceDegrees(self.rotationZ, targetAngle);
  if (angleDifference === null || angleDifference > playerTargeting.maxAngleDegrees) {
    return null;
  }

  return {
    peer,
    distance: Math.sqrt((planarDistance * planarDistance) + (dz * dz)),
    angleDifference
  };
}

function aimedPeer(peers, selfPosition) {
  const scored = peers
    .map((peer) => peerAimScore(peer, selfPosition))
    .filter(Boolean)
    .sort((left, right) => (
      left.angleDifference - right.angleDifference
      || left.distance - right.distance
    ));

  if (scored[0]) {
    return scored[0].peer;
  }

  const hasAnyPeerPosition = peers.some((peer) => validPosition(peer?.position));
  return hasAnyPeerPosition ? null : (peers[0] || null);
}

function firstJobBoardEntry(jobs) {
  return jobs.find((job) => job.boardCode) || jobs[0] || null;
}

function jobCode(job) {
  return label(job?.jobCode || job?.code, '');
}

function jobBoardCode(job) {
  return label(job?.boardCode || job?.job?.boardCode || job?.details?.boardCode, '');
}

function accountStipendReady(stipend) {
  return stipend?.ready === true || stipend?.status === 'ready';
}

function firstClaimableJob(jobs, owner) {
  return claimableJobEntries(jobs, owner, 1)[0] || null;
}

function claimableJobEntries(jobs, owner, limit = 3) {
  const claimed = claimedJobCodes(owner);
  return optionalArray(jobs)
    .filter((job) => {
      const code = jobCode(job);
      return code && !claimed.has(code);
    })
    .slice(0, limit);
}

function jobsForBoard(owner, boardCode) {
  const available = owner?.available || {};
  const cleanBoardCode = label(boardCode, '');
  const jobs = optionalArray(available.jobBoard);
  return cleanBoardCode
    ? jobs.filter((job) => label(job?.boardCode, '') === cleanBoardCode)
    : jobs;
}

function firstActiveJobForBoard(owner, boardCode) {
  const cleanBoardCode = label(boardCode, '');
  const activeJobs = optionalArray(owner?.jobs)
    .filter((job) => !job.status || job.status === 'claimed');
  return (cleanBoardCode
    ? activeJobs.find((job) => jobBoardCode(job) === cleanBoardCode)
    : null)
    || activeJobs[0]
    || null;
}

function firstClaimableJobForBoard(owner, boardCode) {
  return firstClaimableJob(jobsForBoard(owner, boardCode), owner);
}

function latestClaimedJobForBoard(storage, owner, boardCode) {
  const event = storage?.skyrimRpJobEvent;
  const claim = event?.type === 'job_claim_result' ? event.claim : null;
  if (!claim?.id || claim.status !== 'claimed') {
    return null;
  }

  const cleanBoardCode = label(boardCode, '');
  const claimBoardCode = jobBoardCode(claim);
  if (cleanBoardCode && claimBoardCode) {
    return claimBoardCode === cleanBoardCode ? claim : null;
  }

  if (!cleanBoardCode) {
    return claim;
  }

  const claimCode = jobCode(claim);
  const boardJobCodes = new Set(jobsForBoard(owner, cleanBoardCode).map(jobCode).filter(Boolean));
  if (boardJobCodes.size > 0 && !boardJobCodes.has(claimCode)) {
    return null;
  }

  return claim;
}

function codeFromEntry(entry) {
  if (typeof entry === 'string') {
    return entry.toLowerCase();
  }

  return String(entry?.professionCode || entry?.guildCode || entry?.code || entry?.name || entry?.type || '').toLowerCase();
}

function ownerCodeSet(owner) {
  const roles = [
    ...optionalArray(owner.roles),
    ...optionalArray(owner.accountRoles),
    ...optionalArray(owner.staffRoles)
  ].map((role) => String(role || '').toLowerCase());
  const memberships = [
    ...professionMemberships(owner),
    ...optionalArray(owner.professions)
      .filter((entry) => label(entry?.membershipStatus || entry?.status, '').toLowerCase() === 'active')
  ].map(codeFromEntry);

  const guilds = [
    ...optionalArray(owner.guildMemberships),
    ...optionalArray(owner.guilds)
  ].map(codeFromEntry);

  return new Set([...roles, ...memberships, ...guilds].filter(Boolean));
}

function professionMembershipRecords(owner) {
  return optionalArray(owner?.professionMemberships);
}

function professionMemberships(owner) {
  return professionMembershipRecords(owner)
    .filter((membership) => membership?.status === undefined || membership.status === 'active');
}

function professionCode(entry) {
  return label(entry?.professionCode || entry?.code, '').toLowerCase();
}

const nonKProfessionCodes = new Set([
  'merchant',
  'innkeeper',
  'tavern_owner',
  'business_owner',
  'property_steward',
  'building_manager',
  'guild_property_manager',
  'guild_key_manager',
  'guild_key_revoker',
  'guild_room_assigner'
]);

function isKProfessionCode(code) {
  const cleanCode = label(code, '').toLowerCase();
  return Boolean(cleanCode && !nonKProfessionCodes.has(cleanCode));
}

function activeProfessionCodes(owner) {
  return new Set(professionMemberships(owner).map(professionCode).filter(isKProfessionCode));
}

function primaryProfessionMembership(memberships) {
  return memberships.find((membership) => (
    membership?.isPrimary === true
    || label(membership?.pathType, '').toLowerCase() === 'primary'
  )) || memberships[0] || null;
}

function activeProfessionInvitationCodes(owner) {
  return new Set(optionalArray(owner?.professionInvitations)
    .filter((invitation) => invitation?.status === undefined || invitation.status === 'active')
    .map((invitation) => label(invitation?.professionCode, '').toLowerCase())
    .filter(isKProfessionCode));
}

function activeProfessionInvitationForCode(owner, professionCodeValue) {
  const cleanCode = label(professionCodeValue, '').toLowerCase();
  if (!cleanCode) {
    return null;
  }

  return optionalArray(owner?.professionInvitations)
    .find((invitation) => (
      (invitation?.status === undefined || invitation.status === 'active')
      && label(invitation?.professionCode, '').toLowerCase() === cleanCode
      && label(invitation?.id, '') !== ''
    )) || null;
}

function primaryProfession(owner) {
  const memberships = professionMembershipRecords(owner)
    .filter((membership) => isKProfessionCode(professionCode(membership)));
  const primary = primaryProfessionMembership(memberships);
  if (!primary) {
    return null;
  }

  const progress = optionalArray(owner?.professions)
    .find((profession) => professionCode(profession) === professionCode(primary));
  return {
    ...progress,
    ...primary,
    code: professionCode(primary),
    displayName: label(primary.professionDisplayName || progress?.displayName, 'Profession')
  };
}

function professionLevelInfo(profession) {
  const xp = Math.max(0, Number(profession?.xp || 0));
  const level = Math.max(1, Number(profession?.level || professionLevelFromXp(xp)));
  const currentLevelXp = professionXpThresholdForLevel(level);
  const nextLevelXp = professionXpThresholdForLevel(level + 1);
  const intoLevel = Math.max(0, xp - currentLevelXp);
  const needed = Math.max(0, nextLevelXp - xp);
  const levelSpan = Math.max(1, nextLevelXp - currentLevelXp);
  return {
    xp,
    level,
    currentLevelXp,
    nextLevelXp,
    intoLevel,
    needed,
    percent: Math.max(0, Math.min(100, Math.round((intoLevel / levelSpan) * 100)))
  };
}

function professionXpThresholdForLevel(level) {
  const cleanLevel = Math.max(1, Number(level || 1));
  if (cleanLevel <= PROFESSION_LEVEL_THRESHOLDS.length) {
    return PROFESSION_LEVEL_THRESHOLDS[cleanLevel - 1];
  }

  return PROFESSION_LEVEL_THRESHOLDS.at(-1) + ((cleanLevel - PROFESSION_LEVEL_THRESHOLDS.length) * 275);
}

function professionLevelFromXp(xp) {
  const cleanXp = Math.max(0, Number(xp || 0));
  let level = 1;
  for (let index = 1; index < PROFESSION_LEVEL_THRESHOLDS.length; index += 1) {
    if (cleanXp >= PROFESSION_LEVEL_THRESHOLDS[index]) {
      level = index + 1;
    }
  }

  if (level === PROFESSION_LEVEL_THRESHOLDS.length) {
    const extraXp = cleanXp - PROFESSION_LEVEL_THRESHOLDS.at(-1);
    level += Math.floor(extraXp / 275);
  }

  return level;
}

function fallbackProfessionEntry(entry, source = 'membership') {
  const code = professionCode(entry);
  if (!code) {
    return null;
  }

  return {
    ...entry,
    code,
    professionCode: code,
    displayName: label(entry?.professionDisplayName || entry?.displayName, humanizedCode(code, 'Profession')),
    category: label(entry?.category, 'profession'),
    description: label(entry?.description, source === 'invitation'
      ? 'Secondary profession invitation. Unlocking it keeps your primary profession unchanged.'
      : 'Your chosen profession. XP, recipes, crafting, and profession-only work stay here.'),
    joinRule: source === 'invitation' ? 'invitation' : label(entry?.joinRule, 'open'),
    visibility: label(entry?.visibility, 'public'),
    xp: Math.max(0, Number(entry?.xp || 0)),
    level: Math.max(1, Number(entry?.level || 1))
  };
}

