function shortDateLabel(value) {
  const text = label(value, '');
  return text ? text.slice(0, 10) : '';
}

function propertyRecoveryDeadlineLabel(recoveryCase) {
  const pickupDeadline = shortDateLabel(recoveryCase?.pickupDeadlineAt);
  if (pickupDeadline) {
    return `Pickup by ${pickupDeadline}`;
  }

  const auctionEligible = shortDateLabel(recoveryCase?.auctionEligibleAt);
  if (auctionEligible) {
    return `Auction after ${auctionEligible}`;
  }

  const saleEligible = shortDateLabel(recoveryCase?.saleEligibleAt);
  if (saleEligible) {
    return `Sale after ${saleEligible}`;
  }

  return '';
}

function propertyRecoveryStorageLabel(recoveryCase) {
  const quantity = Number(recoveryCase?.storageQuantity || 0);
  const itemCount = Number(recoveryCase?.storageItemCount || 0);
  if (quantity > 0) {
    return `Storage: ${quantity} item${quantity === 1 ? '' : 's'}`;
  }
  if (itemCount > 0) {
    return `Storage: ${itemCount} stack${itemCount === 1 ? '' : 's'}`;
  }
  return 'Storage: empty or unreported';
}

function firstOpenPropertyRecoveryCase(cases) {
  return cases.find((recoveryCase) => ['pickup', 'recovery'].includes(label(recoveryCase?.status, '').toLowerCase()))
    || cases.find((recoveryCase) => label(recoveryCase?.status, '').toLowerCase() === 'auction_ready')
    || cases[0]
    || null;
}

function claimedJobCodes(owner) {
  return new Set(optionalArray(owner.jobs)
    .map(jobCode)
    .filter(Boolean));
}

function resourceStateLabel(resource) {
  if (!resource) {
    return '';
  }

  if (resource.state && resource.state !== 'available') {
    return `State: ${resource.state}`;
  }

  const yieldQuantity = Number(resource.yieldQuantity || 0);
  const item = label(resource.itemDisplayName || resource.itemCode, '');
  if (yieldQuantity > 0 && item) {
    return `Yields ${yieldQuantity} ${item}`;
  }

  return 'Available';
}

function propertyRentLabel(property) {
  const rent = Number(property?.rentAmount ?? property?.rent ?? property?.price ?? 0);
  return rent > 0 ? `Rent: ${rent} gold` : 'Rent uses Skyrim gold';
}

function propertyPurchaseLabel(property) {
  const price = Number(property?.purchasePrice ?? property?.price ?? 0);
  return price > 0 ? `Price: ${price} gold` : 'Not listed for purchase';
}

function firstPropertyLock(property) {
  return optionalArray(property?.locks).find((lock) => label(lock?.targetCode, '')) || null;
}

function firstInventoryItem(owner) {
  return optionalArray(owner?.inventory).find((item) => label(item?.itemCode || item?.code, '') && Number(item?.quantity || 0) > 0) || null;
}

function inventoryLists(owner) {
  return [
    ...optionalArray(owner?.inventory),
    ...optionalArray(owner?.items)
  ];
}

function inventoryKnown(owner) {
  return Array.isArray(owner?.inventory) || Array.isArray(owner?.items);
}

function inventoryContains(owner, itemCode) {
  const code = label(itemCode, '').toLowerCase();
  if (!code) {
    return true;
  }

  const items = inventoryLists(owner);
  if (!inventoryKnown(owner)) {
    return null;
  }

  return items.some((item) => label(item?.itemCode || item?.code, '').toLowerCase() === code && Number(item?.quantity || 0) > 0);
}

function inventoryQuantity(owner, itemCode) {
  const code = label(itemCode, '').toLowerCase();
  if (!code) {
    return 0;
  }

  const items = inventoryLists(owner);
  if (!inventoryKnown(owner)) {
    return null;
  }

  return items.reduce((sum, item) => (
    label(item?.itemCode || item?.code, '').toLowerCase() === code
      ? sum + Math.max(0, Number(item?.quantity || 0))
      : sum
  ), 0);
}

function resourceProfessionCode(resource) {
  return label(resource?.requiredProfessionCode || resource?.resourceType, '').toLowerCase();
}

function dungeonEncounterCode(encounter) {
  return label(encounter?.code || encounter?.encounterCode, '').toLowerCase();
}

function dungeonEncounterList(owner, state = {}) {
  return uniqueRecords([
    ...optionalArray(owner?.available?.dungeonEncounters),
    ...optionalArray(owner?.dungeonEncounters),
    ...optionalArray(state?.dungeonEncounters)
  ]).filter((encounter) => dungeonEncounterCode(encounter));
}

function dungeonEncounterForAnchor(owner, state, anchorCode) {
  const cleanAnchor = label(anchorCode, '').toLowerCase();
  if (!cleanAnchor) {
    return null;
  }

  return dungeonEncounterList(owner, state)
    .find((encounter) => (
      dungeonEncounterCode(encounter) === cleanAnchor
      || label(encounter?.worldReferenceCode, '').toLowerCase() === cleanAnchor
    )) || null;
}

function dungeonEncounterGate(encounter, canAct) {
  const reasons = [];
  const state = label(encounter?.state, 'ready').toLowerCase();
  const activeSpawnCount = Number(encounter?.activeSpawnCount || 0);

  if (!canAct) {
    reasons.push('join the server');
  }

  if (encounter?.active === false || state === 'inactive') {
    reasons.push('encounter is inactive');
  }

  if (activeSpawnCount > 0 || state === 'active') {
    reasons.push('clear the active encounter spawns');
  }

  if (encounter?.cooldownActive === true || state === 'cooldown') {
    const cooldownUntil = shortDateLabel(encounter?.cooldownUntil);
    reasons.push(cooldownUntil ? `cooling down until ${cooldownUntil}` : 'encounter is cooling down');
  }

  return {
    enabled: reasons.length === 0,
    reasons
  };
}

function dungeonEncounterDetail(encounter, gate) {
  const tier = label(encounter?.tier, 'starter');
  const recommendedLevel = Number(encounter?.recommendedLevel || 1);
  const cooldownSeconds = Number(encounter?.cooldownSeconds || 0);
  const spawnCount = Number(encounter?.spawnCount || optionalArray(encounter?.spawns).length || 0);
  const reward = encounter?.completionReward || {};
  const rewardParts = [
    Number(reward.gold || 0) > 0 ? `${Number(reward.gold)} gold` : '',
    reward.itemCode && Number(reward.itemQuantity || 0) > 0
      ? `${Number(reward.itemQuantity)} ${label(reward.itemDisplayName || reward.itemCode, 'item')}`
      : '',
    reward.professionCode && Number(reward.xp || 0) > 0
      ? `${Number(reward.xp)} ${label(reward.professionDisplayName || reward.professionCode, 'Profession')} XP`
      : ''
  ].filter(Boolean);
  return [
    `Tier: ${humanizedCode(tier, tier)}`,
    `Recommended level ${recommendedLevel}`,
    spawnCount > 0 ? `${spawnCount} spawn${spawnCount === 1 ? '' : 's'}` : '',
    rewardParts.length > 0 ? `Clear reward: ${rewardParts.join(', ')}` : '',
    cooldownSeconds > 0 ? `Cooldown ${compactSeconds(cooldownSeconds)}` : '',
    label(encounter?.cell, ''),
    'Hunting profession can skin loot and XP after kills',
    gate.enabled ? 'Ready to start' : `Needs: ${gate.reasons.join(', ')}`
  ].filter(Boolean);
}

function resourceProfessionLabel(resource) {
  const code = resourceProfessionCode(resource);
  return label(resource?.professionDisplayName || resource?.resourceTypeDisplayName, humanizedCode(code, 'Profession'));
}

function resourceToolLabel(resource) {
  return label(resource?.requiredToolDisplayName, humanizedCode(resource?.requiredToolCode, resource?.requiredToolCode || 'Tool'));
}

function resourceGatherGate(resource, owner, canAct) {
  const reasons = [];
  const state = label(resource?.state, 'available').toLowerCase();
  const profession = resourceProfessionCode(resource);
  const toolCode = label(resource?.requiredToolCode, '');
  const ownsTool = inventoryContains(owner, toolCode);
  const canChooseProfession = profession
    && (!primaryProfession(owner) || activeProfessionInvitationCodes(owner).has(profession));

  if (!canAct) {
    reasons.push('join the server');
  }

  if (state && state !== 'available') {
    reasons.push(state === 'depleted' ? 'resource is depleted' : `resource is ${state}`);
  }

  if (profession && !activeProfessionCodes(owner).has(profession)) {
    reasons.push(canChooseProfession
      ? `choose ${resourceProfessionLabel(resource)} in K`
      : `requires ${resourceProfessionLabel(resource)} profession`);
  }

  if (toolCode && ownsTool === false) {
    reasons.push(`missing ${resourceToolLabel(resource)}`);
  }

  return {
    enabled: reasons.length === 0,
    reasons
  };
}

function resourceContextDetails(resource, owner, gate) {
  const profession = resourceProfessionCode(resource);
  const toolCode = label(resource?.requiredToolCode, '');
  const toolStatus = inventoryContains(owner, toolCode);
  const professionActive = activeProfessionCodes(owner).has(profession);
  const canChooseProfession = profession
    && (!primaryProfession(owner) || activeProfessionInvitationCodes(owner).has(profession));
  const details = [resourceStateLabel(resource)];

  if (profession) {
    details.push(`Profession: ${resourceProfessionLabel(resource)}${professionActive ? ' (chosen)' : canChooseProfession ? ' (choose in K)' : ' (not chosen)'}`);
  }

  if (toolCode) {
    const status = toolStatus === true ? ' (owned)' : (toolStatus === false ? ' (missing)' : '');
    details.push(`Tool: ${resourceToolLabel(resource)}${status}`);
  }

  details.push(gate.enabled
    ? 'Ready: gathers materials and profession XP'
    : `Needs: ${gate.reasons.join(', ')}`);

  return details.filter(Boolean);
}

