function uniqueRecords(records) {
  const seen = new Set();
  const result = [];
  for (const record of records) {
    const id = label(record?.id || record?.code, '');
    const key = id || JSON.stringify(record);
    if (!key || seen.has(key)) {
      continue;
    }

    seen.add(key);
    result.push(record);
  }
  return result;
}

