function settingEnabled(value: unknown, defaultValue = true) {
  if (value === undefined || value === null || value === '') {
    return defaultValue;
  }
  if (typeof value === 'boolean') {
    return value;
  }
  if (typeof value === 'number') {
    return value !== 0;
  }
  if (typeof value === 'string') {
    const normalized = value.trim().toLowerCase();
    if (['false', '0', 'no', 'off'].includes(normalized)) {
      return false;
    }
    if (['true', '1', 'yes', 'on'].includes(normalized)) {
      return true;
    }
  }

  return Boolean(value);
}

function settingText(value: unknown, fallback = '') {
  return typeof value === 'string' && value.trim() !== '' ? value.trim() : fallback;
}

function validateConsoleCell(value: string) {
  const cell = value.trim();
  if (!/^[A-Za-z0-9_]+$/.test(cell)) {
    throw new Error(`Stage 1 test cell '${value}' must be a vanilla console cell EditorID`);
  }

  return cell;
}

function parseFormIdSetting(value: unknown, fallback: number) {
  if (value === undefined || value === null || value === '') {
    return fallback;
  }

  if (typeof value === 'number' && Number.isFinite(value)) {
    return value;
  }

  if (typeof value === 'string') {
    const trimmed = value.trim();
    const parsed = trimmed.toLowerCase().startsWith('0x')
      ? Number.parseInt(trimmed.slice(2), 16)
      : Number.parseInt(trimmed, 10);
    if (Number.isFinite(parsed)) {
      return parsed;
    }
  }

  throw new Error(`Stage 1 world/cell form ID '${String(value)}' is invalid`);
}

function parseVectorSetting(value: unknown, fallback: number[]) {
  if (Array.isArray(value)) {
    const parsed = value.map((part) => Number(part));
    if (parsed.length === 3 && parsed.every(Number.isFinite)) {
      return parsed;
    }
  }

  if (typeof value === 'string' && value.trim() !== '') {
    const parsed = value
      .split(/[,\s]+/)
      .filter(Boolean)
      .map((part) => Number(part));
    if (parsed.length === 3 && parsed.every(Number.isFinite)) {
      return parsed;
    }
  }

  return [...fallback];
}

function formatFormId(value: number) {
  return `0x${Math.trunc(value).toString(16)}`;
}

function objectKeys(value: unknown) {
  if (!value || typeof value !== 'object') {
    return [];
  }

  return Object.keys(value as Record<string, unknown>);
}

function splitKeySetting(value: string) {
  return value
    .split(/[,\s;]+/)
    .map((entry) => entry.trim())
    .filter(Boolean);
}

function uniqueKeys(keys: string[]) {
  const seen = new Set<string>();
  const result: string[] = [];
  for (const key of keys) {
    const normalized = key.toLowerCase();
    if (seen.has(normalized)) {
      continue;
    }
    seen.add(normalized);
    result.push(key);
  }
  return result;
}

function normalizedKeyName(key: string) {
  return String(key || '').trim().toUpperCase();
}

function isUnboundKeyName(key: string) {
  const normalized = normalizedKeyName(key);
  return !normalized || ['UNBOUND', 'NONE', 'DISABLED', 'OFF'].includes(normalized);
}

function isDisabledVanillaControlKeyName(key: string) {
  const normalized = normalizedKeyName(key);
  return Boolean(normalized && disabledVanillaControlKeys()
    .some((disabledKey) => normalizedKeyName(disabledKey) === normalized));
}

function rpMenuKeySetting(value: unknown, fallback: string) {
  const key = settingText(value, fallback);
  return isDisabledVanillaControlKeyName(key) ? fallback : key;
}

function rpMenuKeyList(keys: string[]) {
  return uniqueKeys(keys).filter((key) => !isUnboundKeyName(key) && !isDisabledVanillaControlKeyName(key));
}

function normalizeStringMap(value: unknown): Record<string, string> {
  if (!value) {
    return {};
  }

  if (typeof value === 'object') {
    return Object.fromEntries(Object.entries(value as Record<string, unknown>)
      .map(([key, entry]) => [String(key), String(entry || '').trim()])
      .filter(([_key, entry]) => entry !== ''));
  }

  if (typeof value !== 'string') {
    return {};
  }

  try {
    return normalizeStringMap(JSON.parse(value));
  } catch {
    const map: Record<string, string> = {};
    for (const entry of value.split(/[;\n]/)) {
      const [key, mapped] = entry.split('=').map((part) => part?.trim());
      if (key && mapped) {
        map[key] = mapped;
      }
    }
    return map;
  }
}

function normalizeFormId(value: unknown): string {
  if (value === undefined || value === null || value === '') {
    return '';
  }

  if (typeof value === 'number' && Number.isFinite(value)) {
    return Math.trunc(value).toString(16).padStart(8, '0').toLowerCase();
  }

  if (typeof value !== 'string') {
    return '';
  }

  const trimmed = value.trim().toLowerCase();
  if (!trimmed) {
    return '';
  }

  const withoutPrefix = trimmed.startsWith('0x') ? trimmed.slice(2) : trimmed;
  if (/^[0-9a-f]+$/.test(withoutPrefix)) {
    return withoutPrefix.padStart(8, '0').slice(-8).toLowerCase();
  }

  const parsed = Number.parseInt(trimmed, 10);
  return Number.isFinite(parsed)
    ? Math.trunc(parsed).toString(16).padStart(8, '0').toLowerCase()
    : '';
}

function normalizeActivationMapKey(value: string) {
  const clean = String(value || '').trim().toLowerCase();
  if (!clean) {
    return '';
  }

  const localPrefixed = clean.match(/^(ref-local|base-local|local):(.+)$/);
  if (localPrefixed) {
    const formId = normalizeFormId(localPrefixed[2]);
    return formId ? `${localPrefixed[1]}:${formId.slice(2)}` : '';
  }

  const prefixed = clean.match(/^(ref|base|form):(.+)$/);
  if (prefixed) {
    const formId = normalizeFormId(prefixed[2]);
    return formId ? `${prefixed[1]}:${formId}` : '';
  }

  return normalizeFormId(clean);
}

function normalizeActivationMap(value: unknown): Record<string, string> {
  const raw = normalizeStringMap(value);
  const map: Record<string, string> = {};
  for (const [key, anchorCode] of Object.entries(raw)) {
    const normalized = normalizeActivationMapKey(key);
    const cleanAnchorCode = settingText(anchorCode);
    if (normalized && cleanAnchorCode) {
      map[normalized] = cleanAnchorCode;
      const prefixed = normalized.match(/^(ref|base|form):([0-9a-f]{8})$/);
      if (prefixed) {
        map[`${prefixed[1]}-local:${prefixed[2].slice(2)}`] = cleanAnchorCode;
      } else if (/^[0-9a-f]{8}$/.test(normalized)) {
        map[`local:${normalized.slice(2)}`] = cleanAnchorCode;
      }
    }
  }

  return map;
}

function resolvePluginSettings(allSettings: Record<string, Record<string, unknown>>) {
  return allSettings['skyrim-rp-client']
    || allSettings['skyrim-rp']
    || {};
}

