function log(message: string) {
  const line = `[SkyrimRP] ${message}`;
  try {
    printConsole(line);
  } catch {
    // Keep logging failures from breaking menu-time networking.
  }

  try {
    Debug.notification(line);
  } catch {
    // Notifications are not available in every SkyrimPlatform lifecycle phase.
  }

  if (message.startsWith('phase=')) {
    markMenuDirty();
  }
}

function markMenuDirty() {
  menuController?.markDirty();
}

function safeRead<T>(reader: () => T, fallback: T): T {
  try {
    const value = reader();
    return value === undefined || value === null ? fallback : value;
  } catch {
    return fallback;
  }
}

function safeNumberRead(reader: () => number | undefined | null, fallback = 0) {
  const value = safeRead(reader, fallback);
  return Number.isFinite(Number(value)) ? Number(value) : fallback;
}

function readActualPlayerPosition() {
  const player = safeRead(() => Game.getPlayer(), null);
  const worldspace = safeRead(() => player?.getWorldSpace()?.getName(), '') || 'unknown';
  const cell = safeRead(() => player?.getParentCell()?.getName(), '') || 'unknown';

  return {
    playerAvailable: Boolean(player),
    worldspace,
    cell,
    x: safeNumberRead(() => player?.getPositionX()),
    y: safeNumberRead(() => player?.getPositionY()),
    z: safeNumberRead(() => player?.getPositionZ()),
    rotationZ: safeNumberRead(() => player?.getAngleZ())
  };
}

