function text(value, fallback = '') {
  return typeof value === 'string' && value.trim() !== '' ? value.trim() : fallback;
}

function numberValue(value, fallback = 0) {
  const parsed = Number(value);
  return Number.isFinite(parsed) ? parsed : fallback;
}

function locationKey(value) {
  return text(value, 'unknown').toLowerCase().replace(/[^a-z0-9]/g, '');
}

const worldspaceAliases = new Map([
  ['skyrim', 'Tamriel'],
  ['tamriel', 'Tamriel']
]);

const cellAliases = new Map([
  ['sleepinggiantinn', 'RiverwoodSleepingGiantInn'],
  ['riverwoodsleepinggiantinn', 'RiverwoodSleepingGiantInn']
]);

function canonicalWorldspace(value) {
  const original = text(value, 'unknown');
  return worldspaceAliases.get(locationKey(original)) || original;
}

function canonicalCell(value) {
  const original = text(value, 'unknown');
  return cellAliases.get(locationKey(original)) || original;
}

function nodePosition(node) {
  return {
    worldspace: canonicalWorldspace(node?.reference?.worldspace || node?.worldspace),
    cell: canonicalCell(node?.reference?.cell || node?.cell),
    x: numberValue(node?.reference?.x ?? node?.x),
    y: numberValue(node?.reference?.y ?? node?.y),
    z: numberValue(node?.reference?.z ?? node?.z)
  };
}

function playerPosition(position) {
  return {
    worldspace: canonicalWorldspace(position?.worldspace),
    cell: canonicalCell(position?.cell),
    x: numberValue(position?.x),
    y: numberValue(position?.y),
    z: numberValue(position?.z)
  };
}

function cellKey(position) {
  const normalized = playerPosition(position);
  if (locationKey(normalized.worldspace) === 'unknown' || locationKey(normalized.cell) === 'unknown') {
    return '';
  }

  return `${locationKey(normalized.worldspace)}/${locationKey(normalized.cell)}`;
}

function sameCell(a, b) {
  const left = cellKey(a);
  return left !== '' && left === cellKey(b);
}

function distanceSquared(a, b) {
  const dx = numberValue(a?.x) - numberValue(b?.x);
  const dy = numberValue(a?.y) - numberValue(b?.y);
  const dz = numberValue(a?.z) - numberValue(b?.z);
  return dx * dx + dy * dy + dz * dz;
}

function availableByTime(node, nowIso) {
  const availableAt = text(node?.availableAt);
  return availableAt !== '' && availableAt <= nowIso;
}

function isAvailableNode(node, nowIso) {
  return Boolean(node?.enabled !== false)
    && (text(node?.state, 'available') === 'available' || availableByTime(node, nowIso));
}

/**
 * @param {{
 *   getPosition?: () => Record<string, unknown>,
 *   requestResourceNodes?: (filters?: Record<string, unknown>) => boolean,
 *   gatherResourceNode?: (nodeCode: string) => boolean,
 *   storage?: Record<string, unknown> | null,
 *   logger?: (message: string) => void,
 *   onBridgeEvent?: (event: Record<string, unknown>) => void,
 *   localCellOnly?: boolean,
 *   gatherRadius?: number,
 *   autoRequestOnCellChange?: boolean,
 *   requestCooldownMs?: number,
 *   now?: () => number
 * }} options
 */
export function createResourceNodeBridge({
  getPosition = () => ({}),
  requestResourceNodes = (_filters = {}) => false,
  gatherResourceNode = (_nodeCode) => false,
  storage = null,
  logger = (_message) => {},
  onBridgeEvent = (_event) => {},
  localCellOnly = true,
  gatherRadius = 180,
  autoRequestOnCellChange = true,
  requestCooldownMs = 1500,
  now = () => Date.now()
} = {}) {
  const state = {
    nodes: new Map(),
    lastCellKey: '',
    lastRequestAt: 0,
    lastRequestedCellKey: '',
    lastGatherNodeCode: null,
    previousGatherPressed: false,
    lastError: null
  };

  function emitBridgeEvent(event) {
    try {
      onBridgeEvent(event);
    } catch (error) {
      logger(`resource bridge event callback failed: ${error?.message || String(error)}`);
    }
  }

  function snapshotStorage() {
    if (!storage || typeof storage !== 'object') {
      return;
    }

    storage.skyrimRpResourceNodeBridge = {
      nodeCodes: [...state.nodes.keys()],
      availableNodeCodes: [...availableNodes().map((entry) => entry.node.code)],
      lastCellKey: state.lastCellKey,
      lastRequestedCellKey: state.lastRequestedCellKey,
      lastGatherNodeCode: state.lastGatherNodeCode,
      lastError: state.lastError
    };
  }

  function applyNode(node) {
    if (!node?.code) {
      return;
    }

    state.nodes.set(node.code, node);
  }

  function availableNodes(options = {}) {
    const position = playerPosition(getPosition());
    const currentIso = new Date(now()).toISOString();
    const resourceType = text(options.resourceType);
    const maxDistance = Number.isFinite(Number(options.maxDistance))
      ? Number(options.maxDistance)
      : Number(gatherRadius || 0);
    const maxDistanceSquared = maxDistance > 0 ? maxDistance * maxDistance : null;

    return [...state.nodes.values()]
      .filter((node) => isAvailableNode(node, currentIso))
      .filter((node) => !resourceType || text(node.resourceType) === resourceType)
      .filter((node) => !localCellOnly || sameCell(position, nodePosition(node)))
      .map((node) => ({
        node,
        distanceSquared: distanceSquared(position, nodePosition(node))
      }))
      .filter((entry) => maxDistanceSquared === null || entry.distanceSquared <= maxDistanceSquared)
      .sort((a, b) => a.distanceSquared - b.distanceSquared);
  }

  function requestCurrentCell(reason = 'manual') {
    const position = playerPosition(getPosition());
    const key = cellKey(position);
    if (!key) {
      return false;
    }

    const current = now();
    if (state.lastRequestedCellKey === key && current - state.lastRequestAt < requestCooldownMs) {
      return false;
    }

    try {
      const sent = requestResourceNodes({
        worldspace: position.worldspace,
        cell: position.cell
      });
      if (!sent) {
        return false;
      }

      state.lastRequestAt = current;
      state.lastRequestedCellKey = key;
      logger(`resource nodes requested cell=${position.worldspace}/${position.cell} reason=${reason}`);
      emitBridgeEvent({
        bridgeEvent: 'request_sent',
        reason,
        worldspace: position.worldspace,
        cell: position.cell
      });
      snapshotStorage();
      return true;
    } catch (error) {
      state.lastError = error?.message || String(error);
      logger(`resource node request failed: ${state.lastError}`);
      emitBridgeEvent({
        bridgeEvent: 'request_failed',
        reason,
        error: state.lastError
      });
      snapshotStorage();
      return false;
    }
  }

  function gatherNearestAvailable(options = {}) {
    const nearest = availableNodes(options)[0]?.node || null;
    if (!nearest) {
      logger('resource gather skipped: no available node nearby');
      emitBridgeEvent({
        bridgeEvent: 'gather_skipped',
        reason: 'no_available_node'
      });
      snapshotStorage();
      return false;
    }

    try {
      const sent = gatherResourceNode(nearest.code);
      if (!sent) {
        return false;
      }

      state.lastGatherNodeCode = nearest.code;
      logger(`resource gather requested nodeCode=${nearest.code}`);
      emitBridgeEvent({
        bridgeEvent: 'gather_requested',
        nodeCode: nearest.code,
        displayName: text(nearest.displayName)
      });
      snapshotStorage();
      return true;
    } catch (error) {
      state.lastError = error?.message || String(error);
      logger(`resource gather failed nodeCode=${nearest.code}: ${state.lastError}`);
      emitBridgeEvent({
        bridgeEvent: 'gather_failed',
        nodeCode: nearest.code,
        error: state.lastError
      });
      snapshotStorage();
      return false;
    }
  }

  function handleGatherInput(pressed) {
    const isPressed = Boolean(pressed);
    const shouldGather = isPressed && !state.previousGatherPressed;
    state.previousGatherPressed = isPressed;
    if (!shouldGather) {
      return false;
    }

    return gatherNearestAvailable();
  }

  function handleResourceEvent(event) {
    if (!event || typeof event !== 'object') {
      return;
    }

    if (event.type === 'snapshot') {
      state.nodes.clear();
      for (const node of Array.isArray(event.nodes) ? event.nodes : []) {
        applyNode(node);
      }
      emitBridgeEvent({
        bridgeEvent: 'snapshot',
        reason: text(event.reason),
        nodeCount: state.nodes.size
      });
      snapshotStorage();
      return;
    }

    const node = event.node || event.result?.node;
    if (node) {
      applyNode(node);
      emitBridgeEvent({
        bridgeEvent: event.type === 'resource_gather_result' ? 'gather_result' : 'updated',
        nodeCode: node.code,
        state: text(node.state)
      });
      snapshotStorage();
    }
  }

  function tick() {
    const key = cellKey(getPosition());
    if (key && key !== state.lastCellKey) {
      state.lastCellKey = key;
      if (autoRequestOnCellChange) {
        requestCurrentCell('cell_changed');
      }
    }

    snapshotStorage();
  }

  return {
    state,
    handleResourceEvent,
    handleGatherInput,
    gatherNearestAvailable,
    requestCurrentCell,
    tick,
    getState() {
      return {
        nodeCodes: [...state.nodes.keys()],
        availableNodeCodes: [...availableNodes().map((entry) => entry.node.code)],
        lastCellKey: state.lastCellKey,
        lastRequestedCellKey: state.lastRequestedCellKey,
        lastGatherNodeCode: state.lastGatherNodeCode,
        lastError: state.lastError
      };
    }
  };
}
